// STUB: Check if roster exists for next month
// If within 5 days of month end and no roster, send warning
// If last day of month and no roster, auto-generate
const now = new Date();
const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
const daysLeft = daysInMonth - now.getDate();

const result = {
  currentDate: now.toISOString(),
  daysLeft: daysLeft,
  shouldWarn: daysLeft <= 5,
  shouldAutoGenerate: daysLeft === 0,
  nextMonth: now.getMonth() + 2,
  nextYear: now.getFullYear()
};

return [{ json: result }];
